UPDATE material SET description = '면(코튼) 천연 셀룰로오스 단일 섬유. 흡습성·통기성·세탁 내구성 우수, 의류·내의·침구·타올 광범위 사용. 폐 면 의류 회수 시 단일 천연 분리 깨끗 — 펄프 재생(한국제지·전주페이퍼·무림페이퍼)·재생 비스코스 원사 두 경로 적합. 솜 충전 재가공 → 매트리스·이불·인형 다용도. 데님 → 데님 순환. 농업 멀칭·바이오매스·자연 분해 친환경 처리. 한국 면 회수 산업 핵심.', update_date = NOW() WHERE code = 'COTTON';

UPDATE material SET description = '폴리에스터(PET) 합성섬유, 내구성·형태 안정성 우수, 운동복·아웃도어·산업용 부직포 다용도. 폐 페트병·폐 폴리 의류 화학 재활용(효성티앤씨 리젠·휴비스 에코에버) → 모노머 회수 → 재생 PET 원사. PET 단일 합성 회수 분류 깨끗·GRS 인증 글로벌 표준. 자동차 흡음재·도아트림·헤드라이너(현대모비스)·건설 단열재(벽산·KCC)·매트리스 충전·신발 인솔·물류 패키징 다방면. PET 화학 재활용 순환경제 핵심.', update_date = NOW() WHERE code = 'POLYESTER';

